import React, { Component, Fragment } from 'react';
import PropTypes from 'prop-types';
import {connect} from 'react-redux';
import {withStyles} from '@material-ui/core/styles';
import { 
    TableCell, FormControl, Switch,
    Chip, TextField, Select, 
    MenuItem, Button, ListItem, FormControlLabel, Checkbox, Menu, IconButton
} from '@material-ui/core';
import { assessmentStrings } from './config';
import { colors } from '../../../utils';
import { MyListCard } from '../../includes';
import { 
    Add as AddIcon, 
    Cancel as CancelIcon, 
    Edit as EditIcon,
    Done as DoneIcon,
    Delete as DeleteIcon
} from '@material-ui/icons';


const style = theme => ({
    root: {
    },
    cell : {
        padding :5,
    },
    track : {
        backgroundColor : colors.secondary + " !important",
        opacity : 0.5 + " !important"
    },
    subjectBtnString : {textTransform : "lowercase"}
})
class _CellMap_Assessments extends Component {
    constructor(props) {
        super(props);
        this.state = {
            name : props.cellMap,
            value : props.row[props.cellMap],
            selectedSubjects : null,
        }
        if(props.getMyContext && props.row.new)
            this.getMyContext(this);

        this.handleChecked = this.handleChecked.bind(this);
        this.handleChange = this.handleChange.bind(this);
    }
    handleChange = name => e =>{
        const value = e.target.value;
        if(name !== "name") this.props.superSetState(
            state=>({
                ...state, 
                newItem : {...state.newItem, [name] : value}
            })
        );
        this.setState({value: value});
    }
    handleChecked = (which, row) => e => {
        const value = e.target.checked;
        if(row.new){
            if(which === "subjects")
                this.props.superSetState(state => 
                ({...state, newItem : {...state.newItem, allSubjects : value}})
            );
            else this.props.superSetState(state => 
                ({...state, newItem : {...state.newItem, allLevels : value}})
            );
        }else{
            console.log("not new");
            this.props.superSetState(state=>{
                const data = [...state.data];
                const {item, index} = data.getFirstObjectByPropValue("_id", row._id);
                if(which === "subjects")
                    item.allSubjects = value;
                else item.allLevels = value;
                data[index] = item;
                return {...data};
            });
        }
    }
    handlePopperBtn = e => {
        const {subjectPoperAnchorEl} = this.state;
        if(subjectPoperAnchorEl)
            this.setState({subjectPoperAnchorEl : null});
        else this.setState({subjectPoperAnchorEl : e.target});
    }
    handleListCompCheckbox = value => e => {
        console.log(e.target.checked);
        const checked = e.target.checked;
        let selectedSubjects; 
        if(this.state.selectedSubjects)
            selectedSubjects = [...this.state.selectedSubjects];  
        else selectedSubjects = [];      
        if(checked)
            selectedSubjects.push(value);
        else 
            selectedSubjects.splice(
                selectedSubjects.indexOf(value), 
                1
            );
        this.setState({selectedSubjects});
    }
    subjectListComponent = selectedSubjects => props => {
        return <ListItem key={props.index}>
            <FormControlLabel
                control={
                    <Checkbox
                        checked={selectedSubjects && selectedSubjects.indexOf(props._id) !== -1}
                        onChange={this.handleListCompCheckbox(props._id)}
                        />
                }
                label={props.name}/>
        </ListItem>
    }
    subjectListSearchOnChange = keyword => {
        console.log("keyword", keyword);
    }
    render() {
        const {
            classes, cellMap, row,
            [assessmentStrings.editMode] : editMode,
            allTerms, levels,
            currentSessionTerms
        } = this.props;
        const {value, selectedSubjects, subjectPoperAnchorEl} = this.state;
        if(row.editing || row.new){
            switch(cellMap){
                case "action" : return <TableCell className={classes.cell}>
                    {row.new ? 
                        <IconButton onClick={()=>{}}>
                            <AddIcon size={30} style={{color : colors.secondary}}/>
                        </IconButton> : 
                        <Fragment>
                            <DoneIcon/>
                            <CancelIcon onClick={this.props.cancelEditButtonHandler(row)}/>
                        </Fragment>
                    }
                </TableCell>
                case "name" : return <TableCell className={classes.cell}>
                    <FormControl>
                        <TextField
                            margin="normal"
                            value={value || ""}
                            placeholder="Name"
                            onChange={this.handleChange("name")}/>
                    </FormControl>
                </TableCell>
                case "subjectIds" : return <TableCell className={classes.cell}>
                    {row.allSubjects ? "All Subjects" :<div>
                        <Button 
                            classes={{
                                label : classes.subjectBtnString
                            }}
                            onClick={this.handlePopperBtn.bind(this)}>
                            {selectedSubjects ? selectedSubjects.length + " subject(s)" : "select subjects"}
                        </Button>
                        <Menu
                            open={Boolean(subjectPoperAnchorEl)}
                            anchorEl={subjectPoperAnchorEl}
                            onClose={e => this.setState({subjectPoperAnchorEl : null})}
                            >
                            <MyListCard
                                elevation={0}
                                list={[{_id: 1, name : "English"}]}
                                itemNameProp="name"
                                searchInputProps={{
                                    style : {width : "100%"},
                                    placeholder : "Search subjects"
                                }}
                                component={this.subjectListComponent(selectedSubjects)}
                                searchOnChange={this.subjectListSearchOnChange.bind(this)}
                                finishBtnName="Finish"
                                finishBtnAction={()=>this.setState({subjectPoperAnchorEl: null})}
                                />
                        </Menu>
                            
                    </div>}
                </TableCell>
                case "termId" :                
                    return <TableCell className={classes.cell}>
                            {row.allLevels ? "All Terms" : 
                                <FormControl>
                                    <Select 
                                        value={value || ""}
                                        inputProps={{
                                            id : "term"
                                        }}
                                        onChange={this.handleChange("termId")}>
                                            {currentSessionTerms && 
                                            currentSessionTerms.map((item, index)=>
                                            <MenuItem key={index} value={item._id}>{item.name}</MenuItem>)}
                                        </Select>
                                </FormControl>
                            }
                        </TableCell>
                case "levelId" :                
                    return <TableCell className={classes.cell}>
                            {row.allLevels ? "All Levels" : 
                                <FormControl>
                                    <Select 
                                        value={value || ""}
                                        inputProps={{
                                            id : "level"
                                        }}
                                        onChange={this.handleChange("levelId", row)}>
                                            {levels && 
                                            levels.map((item, index)=>
                                            <MenuItem key={index} value={item._id}>{item.name}</MenuItem>)}
                                        </Select>
                                </FormControl>
                            }
                        </TableCell>
                case "allSubjects" : return <TableCell className={classes.cell}>
                    <FormControl>
                        <Switch
                            size="small"
                            checked={Boolean(row.allSubjects)}
                            onChange={this.handleChecked("subjects", row)}
                            />
                    </FormControl>
                </TableCell>
                case "allLevels" : return <TableCell className={classes.cell}>
                        <FormControl>
                            <Switch
                                size="small"
                                checked={Boolean(row.allLevels)}
                                onChange={this.handleChecked("levels", row)}
                                />
                        </FormControl>
                    </TableCell>
                default : return <TableCell className={classes.cell}>
                    {row[cellMap]}
                </TableCell>

            }
        }else{

            switch(cellMap){
                case "action" : return <TableCell className={classes.cell}>
                    {row.editable && <EditIcon onClick={this.props.editButtonHandler(row)} fontSize="small" style={{color :colors.gray}}/>}
                    {row.delible && <DeleteIcon color="secondary" fontSize="small"/>}
                </TableCell>
                case "subjectIds" : 
                    let returnSubject = [];
                    if(row.allSubjects){
                        returnSubject = <Chip size="small" label="All subjects"/>;
                    }else{
                        row[cellMap] && row[cellMap].map(
                            (id, i)=>{
                                const {item : subItem} = 
                                row.subjects.getFirstObjectByPropValue("_id", id);
                                returnSubject.push(<Chip key={i} size="small" label={subItem.name}/>);
                            }
                        )
                    }
                    return <TableCell className={classes.cell}>
                        {returnSubject}
                    </TableCell>;
                case "allSubjects" : return <TableCell className={classes.cell}>
                    <FormControl>
                        <Switch
                            size="small"
                            classes={{
                                track : row[cellMap] && classes.track,
                            }}
                            checked={Boolean(row[cellMap])}
                            disabled={Boolean(!editMode)}
                            onChange={()=>{}}
                            />
                    </FormControl>
                </TableCell>
                case "termId" : 
                    let returnVal = null
                    if(row.allLevels){
                        returnVal = "All terms";
                    }else{
                        if(allTerms){
                            const {item, index} = allTerms.getFirstObjectByPropValue("_id", row[cellMap]);
                            returnVal =  item && item.name;
                        }
                    }                
                    return <TableCell className={classes.cell}>
                            {returnVal}
                    </TableCell>
                case "levelId" : 
                    let returnLevel = null
                    if(row.allLevels){
                        returnLevel = "All levels";
                    }else{
                        if(levels){
                            const {item, index} = levels.getFirstObjectByPropValue("_id", row[cellMap]);
                            returnLevel =  item && item.name;
                        }
                    }                
                    return <TableCell className={classes.cell}>
                            {returnLevel}
                    </TableCell>
                case "allLevels" : return <TableCell className={classes.cell}>
                    <FormControl>
                        <Switch
                            size="small"
                            classes={{
                                track : row[cellMap] && classes.track,
                            }}
                            checked={Boolean(row[cellMap])}
                            disabled={Boolean(!editMode)}
                            onChange={()=>{}}
                            />
                    </FormControl>
                </TableCell>
                default : return <TableCell className={classes.cell}>
                    <div>{row[cellMap]}</div>
                </TableCell>
            }
        }
    }
}


_CellMap_Assessments.propTypes = {
    classes : PropTypes.object.isRequired,
    getMyContext : PropTypes.func,
    superSetState : PropTypes.func,

    editButtonHandler : PropTypes.func,
    cancelEditButtonHandler : PropTypes.func,
};
const mapStateToProps = ({assessmentReducer}) => ({
    [assessmentStrings.editMode] : assessmentReducer[assessmentStrings.editMode]
})


export const CellMap_Assessments = connect(mapStateToProps)(withStyles(style)(_CellMap_Assessments));