import React, { Component } from 'react';
import PropTypes from 'prop-types';
import {connect} from 'react-redux';
import {withStyles} from '@material-ui/core/styles';
import { breadCrumbActions, headerStrings, headerActions, mainStageHeaderStrings, mainStageHeaderAction, MyTable, EditableCellMapFormat, MyListCard } from '../../includes';
import { customSuperSetState} from '../../../utils';
import { MainStageComponent_Assessments } from './MainStageComponent_Assessments';
import { CellMap_Assessments } from './CellMap_Assessments';
import { sessionStrings, sessionActions } from '../Sessions';
import { assessmentStrings } from './config';
import { routeNamesSchool } from '../routeNames';

const data = [
    {_id : 1, name : "First Test", allLevels : true,  allSubjects : true},
    {_id : 2, name : "Mock Test", allSubjects : false, levelId :1, termId : 1, allSubjects : true},
    {
        _id : 3,
        name : "Mock Test", allSubjects : false, 
        levelId :1, termId : 1, allSubjects : false, 
        subjectIds : [1, 2],
        subjects : [
            {_id :1, name : "English"},
            {_id :2, name : "Maths"},
        ]
    },
]
const style = theme => ({
    root: {
        marginTop : 20
    }
})
class _Assessments extends Component {
    constructor(props) {
        super(props);
        this.state = {
            newItem : {new : true},
            data : data
        }
        const {dispatch} = props;
        headerActions({
            [headerStrings.headerTitle] : "ASSESSMENTS"
        })(dispatch);
        breadCrumbActions.setBreadCrumb([
            {name : "Dashboard", path : routeNamesSchool.dashboard},
            {name : "Assessments", path : routeNamesSchool.subjectAssessments}
        ])(dispatch);
        mainStageHeaderAction({
            [mainStageHeaderStrings.components] : [
                MainStageComponent_Assessments
            ]
        })(dispatch);
        this.initializeComponent();
        this.mySetState = customSuperSetState(this);
    }
    initializeComponent(){
        const {
            [sessionStrings.levels] : levels,
            [sessionStrings.allTerms] : allTerms,
            [sessionStrings.currentSessionTerms] : currentSessionTerms,
            dispatch
        } = this.props;
        if(!levels) sessionActions.getCurrentSessionLevel()(dispatch);
        if(!allTerms) sessionActions.getAllTerms()(dispatch);
        if(!currentSessionTerms) sessionActions.getCurrentsessionTerms()(dispatch);
    }
    
    cellMapFormat = superProps => props => <CellMap_Assessments {...superProps} {...props}/>
    newInputContexts = [];
    getInputContexts = context => this.newInputContexts.push(context);
    editButtonHandler = row => e => {
        console.log(row);
        const data = [...this.state.data];
        const {index} = data.getFirstObjectByPropValue("_id", row._id);
        data[index].editing = true;
        this.setState({data});
    }
    cancelEditButtonHandler = row => e => {
        const data = [...this.state.data];
        const {index} = data.getFirstObjectByPropValue("_id", row._id);
        delete data[index].editing;
        this.setState({data});
    }
    render() {
        const {
            classes,
            [sessionStrings.levels] : levels,
            [sessionStrings.allTerms] : allTerms,
            [sessionStrings.currentSessionTerms] : currentSessionTerms,
            [assessmentStrings.editMode] : editMode
        } = this.props;
        const {
            newItem
        } = this.state;
        let data;
        data = [...this.state.data];
        if(editMode){
            data = data.map(item => ({...item, editable : true, delible : true}));
            data.push(newItem);
        }
        console.log(data)
        return (
            <div className={classes.root}>
                <MyTable
                    title="Subject Assessments"
                    header={["Name", "All Levels", "Level", "Term", "All Subj.", "Subjects", "Actions"]}
                    dataMap={["name", "allLevels", "levelId", "termId", "allSubjects", "subjectIds", "action"]}
                    CellMap={this.cellMapFormat({
                        levels,
                        allTerms,
                        currentSessionTerms,
                        superSetState : this.mySetState,
                        editButtonHandler : this.editButtonHandler.bind(this),
                        cancelEditButtonHandler : this.cancelEditButtonHandler.bind(this),
                    })}
                    getMyContext={this.getInputContexts.bind(this)}
                    data={data}/>
                    
            </div>
        );
    }
}


_Assessments.propTypes = {
    classes : PropTypes.object.isRequired
};
const mapStateToProps = ({sessionReducer, assessmentReducer}) => ({
    [sessionStrings.levels] : sessionReducer[sessionStrings.levels],
    [sessionStrings.allTerms] : sessionReducer[sessionStrings.allTerms],
    [sessionStrings.currentSessionTerms] : sessionReducer[sessionStrings.currentSessionTerms],
    [assessmentStrings.editMode] : assessmentReducer[assessmentStrings.editMode]
})


export const Assessments = connect(mapStateToProps)(withStyles(style)(_Assessments));
export {Assessments as default};