import React, { Component } from 'react';
import PropTypes from 'prop-types';
import {connect} from 'react-redux';
import {withStyles} from '@material-ui/core/styles';
import { FormControlLabel, Switch, FormControl, Button } from '@material-ui/core';
import { assessmentStrings } from './config';
import { assessmentActions } from './actions';
import { colors } from '../../../utils';


const style = theme => ({
    root: {
    },
    control : {
        padding : 10,
        color : colors.white
    }
})
class _MainStageComponent_Assessments extends Component {
    onChange = e => {
        const {dispatch} = this.props;
        console.log(e.target.checked);
        assessmentActions.setUsePreviousAssessments(e.target.checked)(dispatch);
    }
    setEditMode = e => {
        const {
            dispatch,
            [assessmentStrings.editMode] : editMode
        } = this.props;
        assessmentActions.setEditMode(!editMode)(dispatch);
    }
    render() {
        const {
            classes, 
            [assessmentStrings.usePreviousAssessments] : usePreviousAssessments,
            [assessmentStrings.editMode] : editMode,
        } = this.props;
        return (
            <div className={classes.root}>
                <FormControlLabel
                    className={classes.control}
                    control={
                        <Switch
                            checked={Boolean(usePreviousAssessments)}
                            onChange={this.onChange.bind(this)}
                            inputProps={{
                                id : "usePrev"
                            }}/>
                    }
                    label="Use previous"/>
                <FormControl className={classes.control}>
                    <Button 
                    onClick={()=>this.setEditMode()}
                    variant="contained" style={{
                        backgroundColor : colors.secondary,
                        color : colors.white
                    }}>{editMode ? "Save" : "Edit"}</Button>
                </FormControl>
            </div>
        );
    }
}


_MainStageComponent_Assessments.propTypes = {
    classes : PropTypes.object.isRequired
};
const mapStateToProps = ({assessmentReducer}) => ({
    [assessmentStrings.usePreviousAssessments] : 
        assessmentReducer[assessmentStrings.usePreviousAssessments],
    [assessmentStrings.editMode] : assessmentReducer[assessmentStrings.editMode]
})


export const MainStageComponent_Assessments = connect(mapStateToProps)(withStyles(style)(_MainStageComponent_Assessments));